import{_ as e,o as a,c as i,ae as s}from"./chunks/framework.DTwQaIIa.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/introduction.md","filePath":"en/guide/introduction.md"}'),n={name:"en/guide/introduction.md"};function o(r,t,d,l,c,p){return a(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Emaki Series is a set of Java plugins for Minecraft Spigot servers, organized as a multi-module Maven project. The project uses <code>EmakiCoreLib</code> as its shared foundation library, supporting RPG gameplay modules including attributes &amp; combat, forging, strengthening, cooking, equipment gems, and active skills.</p><h2 id="project-snapshot" tabindex="-1">Project Snapshot <a class="header-anchor" href="#project-snapshot" aria-label="Permalink to &quot;Project Snapshot&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Details</th></tr></thead><tbody><tr><td>Project Type</td><td>Minecraft Spigot multi-module Java plugin suite</td></tr><tr><td>Java Baseline</td><td><code>21</code></td></tr><tr><td>API Baseline</td><td><code>Spigot API 1.21.11-R0.1-SNAPSHOT</code></td></tr><tr><td>Text Components</td><td><code>Adventure 4.26.1</code></td></tr><tr><td>Build Tool</td><td>Maven multi-module aggregation</td></tr><tr><td>License</td><td><code>GPL-3.0-only</code></td></tr><tr><td>Repository</td><td><a href="https://github.com/jiuwu02/Emaki_Series" target="_blank" rel="noreferrer">GitHub</a></td></tr></tbody></table><h2 id="current-version-line" tabindex="-1">Current Version Line <a class="header-anchor" href="#current-version-line" aria-label="Permalink to &quot;Current Version Line&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Module</th><th>artifactId</th><th>Version</th></tr></thead><tbody><tr><td>EmakiCoreLib</td><td><code>emaki-corelib</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiAttribute</td><td><code>emaki-attribute</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiForge</td><td><code>emaki-forge</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiStrengthen</td><td><code>emaki-strengthen</code></td><td><code>3.3.0</code></td></tr><tr><td>EmakiCooking</td><td><code>emaki-cooking</code></td><td><code>2.0.0</code></td></tr><tr><td>EmakiGem</td><td><code>emaki-gem</code></td><td><code>1.2.0</code></td></tr><tr><td>EmakiSkills</td><td><code>emaki-skills</code></td><td><code>1.0.0</code></td></tr></tbody></table><h2 id="module-relationships" tabindex="-1">Module Relationships <a class="header-anchor" href="#module-relationships" aria-label="Permalink to &quot;Module Relationships&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>EmakiCoreLib</span></span>
<span class="line"><span>├── EmakiAttribute</span></span>
<span class="line"><span>├── EmakiForge</span></span>
<span class="line"><span>├── EmakiStrengthen</span></span>
<span class="line"><span>├── EmakiCooking</span></span>
<span class="line"><span>├── EmakiGem</span></span>
<span class="line"><span>└── EmakiSkills</span></span></code></pre></div><ul><li><strong>EmakiCoreLib</strong> is a hard dependency for all business modules, providing shared GUI, actions, item sources, configuration, economy, PDC, and runtime services.</li><li><strong>EmakiAttribute</strong> can independently provide attribute and combat calculations, and can also receive attributes written via PDC by Forge / Strengthen / Gem.</li><li><strong>EmakiForge</strong> assembles items and reads material sources through CoreLib, with optional writing of EmakiAttribute attribute data.</li><li><strong>EmakiStrengthen</strong> applies strengthening layers to equipment through the recipe system, with optional integration of strengthening attributes into EmakiAttribute.</li><li><strong>EmakiCooking</strong> leverages CoreLib&#39;s item sources, action system, block bridging, and structured presentation capabilities to support four types of cooking stations and legacy data migration.</li><li><strong>EmakiGem</strong> provides composable equipment progression through equipment templates, socket openers, and gem definitions, with optional integration of gem attributes into EmakiAttribute.</li><li><strong>EmakiSkills</strong> manages active skills through skill unlocking, triggers, and casting modes, with bridging support for MythicMobs and EmakiAttribute.</li></ul><h2 id="repository-structure" tabindex="-1">Repository Structure <a class="header-anchor" href="#repository-structure" aria-label="Permalink to &quot;Repository Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Project/</span></span>
<span class="line"><span>├── EmakiCoreLib/        # Core foundation library</span></span>
<span class="line"><span>├── EmakiAttribute/      # Attribute and combat system</span></span>
<span class="line"><span>├── EmakiForge/          # Forging system</span></span>
<span class="line"><span>├── EmakiStrengthen/     # Strengthening system</span></span>
<span class="line"><span>├── EmakiCooking/        # Cooking system</span></span>
<span class="line"><span>├── EmakiGem/            # Equipment gem system</span></span>
<span class="line"><span>├── EmakiSkills/         # Active skill system</span></span>
<span class="line"><span>└── pom.xml              # Maven parent project</span></span></code></pre></div><h2 id="build-instructions" tabindex="-1">Build Instructions <a class="header-anchor" href="#build-instructions" aria-label="Permalink to &quot;Build Instructions&quot;">​</a></h2><p>The root <code>pom.xml</code> aggregates five modules by default: <code>EmakiCoreLib</code>, <code>EmakiAttribute</code>, <code>EmakiForge</code>, <code>EmakiStrengthen</code>, and <code>EmakiCooking</code>. When a <code>.key</code> file exists in the root directory, the <code>private-modules</code> profile additionally includes <code>EmakiGem</code> and <code>EmakiSkills</code>.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Full build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Local compilation check</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mvn</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -DskipTests</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span></span></code></pre></div><p>After building, each module&#39;s artifacts are output to the corresponding module&#39;s <code>target/</code> directory.</p><h2 id="community" tabindex="-1">Community <a class="header-anchor" href="#community" aria-label="Permalink to &quot;Community&quot;">​</a></h2><ul><li><a href="https://github.com/jiuwu02/Emaki_Series" target="_blank" rel="noreferrer">GitHub Repository</a></li><li><a href="https://discord.gg/FV4GFQbvCM" target="_blank" rel="noreferrer">Discord Community</a></li><li><a href="https://qm.qq.com/q/GqGrzHp0wU" target="_blank" rel="noreferrer">QQ Group</a></li></ul>`,17)])])}const m=e(n,[["render",o]]);export{h as __pageData,m as default};
